/**
 * Parses common environment-style truthy values into a boolean.
 *
 * Treats `1`, `true`, `yes`, and `on` as true. Empty, nullish, and unknown
 * values return the provided default.
 *
 * @param value - Raw value from an environment variable or config source.
 * @param defaultValue - Value to return when `value` is nullish or empty.
 * @returns Whether the value should be treated as true.
 */
export function isTrue(value: unknown, defaultValue = false): boolean {
  if (value === undefined || value === null || value === '') {
    return defaultValue;
  }

  const normalized = String(value).trim().toLowerCase();
  return normalized === '1' || normalized === 'true' || normalized === 'yes' || normalized === 'on';
}
